    /// remove a area
    pub fn remove_area_with_start_vpn(&mut self, start_vpn: VirtPageNum) {
        if let Some((idx, area)) = self
            .areas
            .iter_mut()
            .enumerate()
            .find(|(_, area)| area.vpn_range.get_start() == start_vpn)
        {
            area.unmap(&mut self.page_table);
            self.areas.remove(idx);
            unsafe {
                asm!("sfence.vma");
            }
        }
    }

    /// Remove every mapped page in [start_vpn, end_vpn), keeping the
    /// non-overlapping parts of existing areas. MAP_FIXED and partial munmap
    /// both need the area list to stay in sync with the page table; otherwise
    /// fork will try to map stale overlapping areas again.
    pub fn remove_area_range(&mut self, start_vpn: VirtPageNum, end_vpn: VirtPageNum) {
        if start_vpn >= end_vpn {
            return;
        }
        let old_areas = core::mem::take(&mut self.areas);
        let mut new_areas = Vec::new();
        for mut area in old_areas {
            let area_start = area.vpn_range.get_start();
            let area_end = area.vpn_range.get_end();
            if area_end <= start_vpn || area_start >= end_vpn {
                new_areas.push(area);
                continue;
            }

            let overlap_start = if area_start > start_vpn { area_start } else { start_vpn };
            let overlap_end = if area_end < end_vpn { area_end } else { end_vpn };
            for vpn in VPNRange::new(overlap_start, overlap_end) {
                if self.page_table.translate(vpn).is_some() {
                    self.page_table.unmap(vpn);
                }
                if area.map_type == MapType::Framed {
                    area.data_frames.remove(&vpn);
                }
            }

            if area_start < overlap_start {
                new_areas.push(area.take_subrange(area_start, overlap_start));
            }
            if overlap_end < area_end {
                new_areas.push(area.take_subrange(overlap_end, area_end));
            }
        }
        self.areas = new_areas;
        unsafe {
            asm!("sfence.vma");
        }
    }
