        if let Some(fd) = (0..self.fd_table.len()).find(|fd| self.fd_table[*fd].is_none()) {
            fd
        } else {
            self.fd_table.push(None);
            self.fd_table.len() - 1
        }
    }
    /// allocate a new file descriptor respecting RLIMIT_NOFILE
    pub fn try_alloc_fd(&mut self) -> Option<usize> {
        let limit = self.rlimits[7][0] as usize;
        if let Some(fd) = (0..self.fd_table.len().min(limit))
            .find(|fd| self.fd_table[*fd].is_none())
        {
            Some(fd)
        } else if self.fd_table.len() < limit {
            self.fd_table.push(None);
            Some(self.fd_table.len() - 1)
        } else {
            None
        }
    }
