    if elf_data[0..4] != [0x7f, 0x45, 0x4c, 0x46] { return false; }
    if elf_data[4] != 2 { return false; } // 64-bit
    // e_phoff at offset 32 (8 bytes, LE)
    let phoff = usize::from_le_bytes(elf_data[32..40].try_into().unwrap_or([0;8]));
    // e_phentsize at offset 54 (2 bytes, LE)
    let phentsize = u16::from_le_bytes(elf_data[54..56].try_into().unwrap_or([0;2])) as usize;
    // e_phnum at offset 56 (2 bytes, LE)
    let phnum = u16::from_le_bytes(elf_data[56..58].try_into().unwrap_or([0;2])) as usize;
    for i in 0..phnum {
        let off = phoff + i * phentsize;
        if off + 8 > elf_data.len() { break; }
        // p_type at offset 0 of phdr (4 bytes, LE)
        let p_type = u32::from_le_bytes(elf_data[off..off+4].try_into().unwrap_or([0;4]));
        if p_type == 3 { return false; } // PT_INTERP = 3
    }
    true
}

struct StaticTlsInfo {
    file_offset: usize,
    file_size: usize,
    mem_size: usize,
    align: usize,
}

fn parse_static_tls(elf_data: &[u8]) -> Option<StaticTlsInfo> {
    if elf_data.len() < 64 {
        return None;
    }
    let phoff = usize::from_le_bytes(elf_data[32..40].try_into().ok()?);
    let phentsize = u16::from_le_bytes(elf_data[54..56].try_into().ok()?) as usize;
    let phnum = u16::from_le_bytes(elf_data[56..58].try_into().ok()?) as usize;
    for i in 0..phnum {
        let off = phoff + i * phentsize;
        if off + 56 > elf_data.len() {
            break;
        }
        let p_type = u32::from_le_bytes(elf_data[off..off + 4].try_into().ok()?);
        if p_type == 7 {
            return Some(StaticTlsInfo {
                file_offset: usize::from_le_bytes(elf_data[off + 8..off + 16].try_into().ok()?),
                file_size: usize::from_le_bytes(elf_data[off + 32..off + 40].try_into().ok()?),
                mem_size: usize::from_le_bytes(elf_data[off + 40..off + 48].try_into().ok()?),
                align: usize::from_le_bytes(elf_data[off + 48..off + 56].try_into().ok()?),
            });
        }
    }
    None
}

fn align_up(value: usize, align: usize) -> usize {
    if align <= 1 {
        value
    } else {
        (value + align - 1) & !(align - 1)
    }
}

fn elf_type(elf_data: &[u8]) -> u16 {
    if elf_data.len() < 18 {
        0
    } else {
        u16::from_le_bytes(elf_data[16..18].try_into().unwrap_or([0; 2]))
    }
}

