/// trait File for all file types
pub trait File: Send + Sync {
    /// the file readable?
    fn readable(&self) -> bool;
    /// the file writable?
    fn writable(&self) -> bool;
    /// read from the file to buf, return the number of bytes read
    fn read(&self, buf: UserBuffer) -> usize;
    /// write to the file from buf, return the number of bytes written
    fn write(&self, buf: UserBuffer) -> usize;
    /// read directory entries into buf, return number of bytes written (0 if not a directory)
    fn getdents(&self, _buf: UserBuffer) -> usize { 0 }
    /// get file status, None if not supported (e.g., pipe, stdio)
    fn stat(&self) -> Option<Stat> { None }
    /// read all file content (byte-level, from beginning)
    fn read_all(&self) -> Vec<u8> { Vec::new() }
    /// read at a fixed file offset without changing the current file position
    fn read_at(&self, _offset: usize, _buf: UserBuffer) -> isize { -38 }
    /// write at a fixed file offset without changing the current file position
    fn write_at(&self, _offset: usize, _buf: UserBuffer) -> isize { -38 }
    /// seek to position; returns new offset or negative error (-38 = ENOSYS for non-seekable)
    fn seek(&self, _offset: isize, _whence: usize) -> isize { -38 }
    /// Socket object id if this file descriptor refers to a socket.
    fn socket_id(&self) -> Option<usize> { None }
    /// File descriptor flags, e.g. FD_CLOEXEC.
    fn fd_flags(&self) -> u32 { 0 }
    /// File status flags, e.g. O_NONBLOCK.
    fn status_flags(&self) -> u32 { 0 }
    /// Stable path key for VFS metadata such as utimensat.
    fn path_key(&self) -> Option<&str> { None }
}

/// A file-descriptor wrapper around a kernel socket table entry.
pub struct SocketFile {
    id: usize,
    fd_flags: u32,
    status_flags: u32,
}

impl SocketFile {
    /// Create a socket file descriptor wrapper for a socket table entry.
    pub fn new(id: usize, fd_flags: u32, status_flags: u32) -> Self {
        Self { id, fd_flags, status_flags }
    }
}

impl Drop for SocketFile {
    fn drop(&mut self) {
        crate::syscall::release_socket(self.id);
    }
}

impl File for SocketFile {
    fn readable(&self) -> bool { true }
    fn writable(&self) -> bool { true }
    fn read(&self, _buf: UserBuffer) -> usize { 0 }
    fn write(&self, buf: UserBuffer) -> usize { buf.len() }
    fn socket_id(&self) -> Option<usize> { Some(self.id) }
    fn fd_flags(&self) -> u32 { self.fd_flags }
    fn status_flags(&self) -> u32 { self.status_flags }
    fn stat(&self) -> Option<Stat> {
        Some(Stat {
            dev: 0, ino: 0, mode: 0o140000, nlink: 1,
            uid: 0, gid: 0, rdev: 0, _pad0: 0,
            size: 0, blksize: 0, _pad1: 0, blocks: 0,
            atime_sec: 0, atime_nsec: 0,
            mtime_sec: 0, mtime_nsec: 0,
            ctime_sec: 0, ctime_nsec: 0,
            _unused: [0; 2],
        })
    }
}

