pub fn get_path_times(path: &str) -> (u64, u64, u64, u64) {
    let table = TIME_TABLE.exclusive_access();
    table
        .iter()
        .find(|(p, _, _, _, _)| p == path)
        .map(|(_, a_sec, a_nsec, m_sec, m_nsec)| (*a_sec, *a_nsec, *m_sec, *m_nsec))
        .unwrap_or((0, 0, 0, 0))
}

pub fn set_path_times(path: &str, a_sec: u64, a_nsec: u64, m_sec: u64, m_nsec: u64) {
    let mut table = TIME_TABLE.exclusive_access();
    if let Some((_, atime_sec, atime_nsec, mtime_sec, mtime_nsec)) =
        table.iter_mut().find(|(p, _, _, _, _)| p == path)
    {
        *atime_sec = a_sec;
        *atime_nsec = a_nsec;
        *mtime_sec = m_sec;
        *mtime_nsec = m_nsec;
    } else {
        table.push((String::from(path), a_sec, a_nsec, m_sec, m_nsec));
    }
}

/// A mount table entry mapping a path prefix to a filesystem
struct MountEntry {
    prefix: String,
    sb: Arc<Ext4SuperBlock>,
}

/// Mount table for managing multiple mounted filesystems
pub struct MountTable {
    entries: Vec<MountEntry>,
}

impl MountTable {
    /// Create a new empty mount table
    fn new() -> Self {
        Self { entries: Vec::new() }
    }

    /// Register a filesystem at a mount point
    pub fn mount(&mut self, prefix: &str, sb: Arc<Ext4SuperBlock>) {
        self.entries.push(MountEntry {
            prefix: String::from(prefix),
            sb,
        });
        self.entries
            .sort_by(|a, b| b.prefix.len().cmp(&a.prefix.len()));
    }

    /// Resolve a path to a mount point and remaining relative path
    pub fn resolve<'a>(&'a self, path: &'a str) -> (&'a str, &'a str) {
        for entry in &self.entries {
            if path.starts_with(&entry.prefix) {
                let rest = &path[entry.prefix.len()..];
                let rest = rest.trim_start_matches('/');
                return (entry.sb.mount_point(), rest);
            }
        }
        (self.entries[0].sb.mount_point(), path.trim_start_matches('/'))
    }

    fn is_mounted(&self, prefix: &str) -> bool {
        self.entries.iter().any(|e| e.prefix == prefix)
    }

    pub fn unmount(&mut self, prefix: &str) -> bool {
        if prefix == "/" {
            return false;
        }
        if let Some(pos) = self.entries.iter().position(|e| e.prefix == prefix) {
            self.entries.remove(pos);
            true
        } else {
            false
        }
    }
}

