// Open flags for file operations (maps to Linux open syscall flags)
bitflags! {
    pub struct OpenFlags: u32 {
        const RDONLY = 0;
        const WRONLY = 1;
        const RDWR = 2;
        const CREATE = 64;
        const TRUNC = 512;
        const DIRECTORY = 0x10000;
        const TMPFILE = 0x410000;
    }
}

impl OpenFlags {
    pub fn read_write(&self) -> (bool, bool) {
        if self.is_empty() {
            (true, false)
        } else if self.contains(Self::WRONLY) {
            (false, true)
        } else {
            (true, true)
        }
    }

    fn to_lwext4_flags(&self) -> u32 {
        let bits = (self.bits() & !(Self::TMPFILE.bits() | Self::DIRECTORY.bits()))
            | if self.contains(Self::TMPFILE) { Self::CREATE.bits() } else { 0 };
        if bits == 0 { O_RDONLY } else { bits }
    }
}

fn build_absolute_path(mount_point: &str, relative_path: &str) -> String {
    if relative_path.is_empty() {
        String::from(mount_point)
    } else if mount_point == "/" {
        format!("/{}", relative_path)
    } else {
        format!("{}/{}", mount_point, relative_path)
    }
}

pub fn canonicalize_path(base: &str, path: &str) -> String {
    let combined = if path.starts_with('/') {
        String::from(path)
    } else if base == "/" {
        format!("/{}", path)
    } else {
        format!("{}/{}", base.trim_end_matches('/'), path)
    };

    let mut components: Vec<&str> = Vec::new();
    for seg in combined.split('/') {
        if seg.is_empty() || seg == "." {
            continue;
        }
        if seg == ".." {
            components.pop();
        } else {
            components.push(seg);
        }
    }
    if components.is_empty() {
        String::from("/")
    } else {
        format!("/{}", components.join("/"))
    }
}

fn path_exists(path: &str) -> bool {
    let normalized = canonicalize_path("/", path);
    let mut file = Ext4File::new(&normalized, InodeTypes::EXT4_DE_REG_FILE);
    file.check_inode_exist(&normalized, InodeTypes::EXT4_DE_REG_FILE) ||
    file.check_inode_exist(&normalized, InodeTypes::EXT4_DE_DIR)
}

