/// fork/clone child process syscall
/// Linux RISC-V: fork and clone share syscall 220
///   fork:  child_sp=0, child inherits parent's sp
///   clone: child_sp≠0, child gets independent stack
///
/// Implements CLONE_PARENT_SETTID and CLONE_CHILD_SETTID so that
/// musl's pthread_create doesn't spin-wait on the child TID.
pub fn sys_fork(_flags: usize, child_sp: usize) -> isize {
    trace!("kernel: sys_fork flags={} child_sp={:#x}", _flags, child_sp);
    // Read extra clone args from trap context (a2=ptid, a4=ctid)
    let (ptid_va, ctid_va, parent_token) = {
        let task = current_task().unwrap();
        let task_inner = task.inner_exclusive_access();
        let trap_cx = task_inner.get_trap_cx();
        let process = task.process.upgrade().unwrap();
        let process_inner = process.inner_exclusive_access();
        (trap_cx.x[12], trap_cx.x[14], process_inner.memory_set.token()) // a2, a4
    };

    let current_process = current_process();
    let new_process = current_process.fork();
    let new_pid = new_process.getpid();
    // modify trap context of new_task, because it returns immediately after switching
    {
        let task = {
            let new_process_inner = new_process.inner_exclusive_access();
            new_process_inner.tasks[0].as_ref().unwrap().clone()
        };
        let task_inner = task.inner_exclusive_access();
        let trap_cx = task_inner.get_trap_cx();
        // we do not have to move to next instruction since we have done it before
        // for child process, fork returns 0
        trap_cx.x[10] = 0; // a0 = 0 for child
        if child_sp != 0 {
            trap_cx.x[2] = child_sp; // RISC-V x2 = sp, switch to child stack
        }
    }

    // CLONE_PARENT_SETTID (0x100000): write new_pid to ptid in parent's address space
    const CLONE_PARENT_SETTID: usize = 0x00100000;
    if (_flags & CLONE_PARENT_SETTID) != 0 && ptid_va != 0 {
        if let Some(r) = try_translated_refmut::<i32>(parent_token, ptid_va as *mut i32) {
            *r = new_pid as i32;
        }
    }

    // CLONE_CHILD_SETTID (0x1000000): write new_pid to ctid in child's address space.
    // Since the child is still COW-sharing physical pages with the parent, writing via
    // the child's page table updates the same physical page the parent reads.
    const CLONE_CHILD_SETTID: usize = 0x01000000;
    if (_flags & CLONE_CHILD_SETTID) != 0 && ctid_va != 0 {
        let child_token = {
            let new_process_inner = new_process.inner_exclusive_access();
            new_process_inner.memory_set.token()
        };
        if let Some(r) = try_translated_refmut::<i32>(child_token, ctid_va as *mut i32) {
            *r = new_pid as i32;
        }
    }

    // CLONE_CHILD_CLEARTID (0x200000): on child exit, write 0 to ctid_va in PARENT's
    // address space and futex-wake, so pthread_join on the parent side unblocks.
    const CLONE_CHILD_CLEARTID: usize = 0x00200000;
    if (_flags & CLONE_CHILD_CLEARTID) != 0 && ctid_va != 0 {
        new_process.inner_exclusive_access().cleartid_va = ctid_va;
    }

    new_pid as isize
}
/// exec syscall
/// Parse PT_INTERP and attempt to load the interpreter binary.
/// Returns (Some(data), true) if interpreter loaded; (None, true) if PT_INTERP present but
/// interpreter not found (PIE-without-linker); (None, false) if truly static (no PT_INTERP).
fn parse_interp_and_load(elf_data: &[u8]) -> (Option<Vec<u8>>, bool) {
    let load = || -> Option<(Option<Vec<u8>>, bool)> {
        if elf_data.len() < 64 { return None; }
        let phoff = usize::from_le_bytes(elf_data[32..40].try_into().ok()?);
        let phentsize = u16::from_le_bytes(elf_data[54..56].try_into().ok()?) as usize;
        let phnum = u16::from_le_bytes(elf_data[56..58].try_into().ok()?) as usize;
        let mut interp_path: Option<&str> = None;
        for i in 0..phnum {
            let off = phoff + i * phentsize;
            if off + 40 > elf_data.len() { break; }
            let p_type = u32::from_le_bytes(elf_data[off..off+4].try_into().ok()?);
            if p_type == 3 { // PT_INTERP
                let p_offset = usize::from_le_bytes(elf_data[off+8..off+16].try_into().ok()?);
                let p_filesz = usize::from_le_bytes(elf_data[off+32..off+40].try_into().ok()?);
                if p_offset + p_filesz > elf_data.len() { break; }
                let bytes = &elf_data[p_offset..p_offset + p_filesz];
                let len = bytes.iter().position(|&b| b == 0).unwrap_or(bytes.len());
                interp_path = core::str::from_utf8(&bytes[..len]).ok();
                break;
            }
        }
        let path = interp_path?; // no PT_INTERP → return None (outer will give (None, false))
        // Try the INTERP path directly first.
        if let Some(f) = open_file(path, OpenFlags::RDONLY) {
            let data = f.read_all();
            if data.len() > 4 && data[0..4] == [0x7f, 0x45, 0x4c, 0x46] {
                return Some((Some(data), true));
            }
        }
        // musl-linked binaries on this sdcard: interp=/lib/ld-musl-* doesn't exist at that
        // path; fall back to the actual musl dynamic linker at /musl/lib/libc.so.
        if path.contains("musl") {
            if let Some(f) = open_file("/musl/lib/libc.so", OpenFlags::RDONLY) {
                let data = f.read_all();
                if data.len() > 4 && data[0..4] == [0x7f, 0x45, 0x4c, 0x46] {
                    return Some((Some(data), true));
                }
            }
        }
        if path.contains("ld-linux-riscv64") {
            if let Some(f) = open_file("/glibc/lib/ld-linux-riscv64-lp64d.so.1", OpenFlags::RDONLY) {
                let data = f.read_all();
                if data.len() > 4 && data[0..4] == [0x7f, 0x45, 0x4c, 0x46] {
                    return Some((Some(data), true));
                }
            }
        }
        // PT_INTERP present but interpreter not found: PIE binary without its linker.
        Some((None, true))
    };
    load().unwrap_or((None, false))
}

