pub const SECTOR_SIZE: usize = 512;

/// VirtIOBlock device driver structure for virtio_blk device
pub struct VirtIOBlock(UPSafeCell<VirtIOBlk<'static, VirtioHal>>);

lazy_static! {
    /// The global io data queue for virtio_blk devices
    static ref QUEUE_FRAMES: UPSafeCell<Vec<FrameTracker>> = unsafe { UPSafeCell::new(Vec::new()) };
}

impl VirtIOBlock {
    /// Read a single 512-byte sector
    pub fn read_sector(&self, sector: usize, buf: &mut [u8; 512]) {
        self.0.exclusive_access().read_block(sector, buf)
            .expect("Error when reading VirtIOBlk");
    }

    /// Write a single 512-byte sector
    pub fn write_sector(&self, sector: usize, buf: &[u8; 512]) {
        self.0.exclusive_access().write_block(sector, buf)
            .expect("Error when writing VirtIOBlk");
    }

    /// Read sectors into buffer
    pub fn read_sectors(&self, sector: usize, buf: &mut [u8]) {
        assert!(buf.len() % SECTOR_SIZE == 0);
        let count = buf.len() / SECTOR_SIZE;
        for i in 0..count {
            let s = &mut buf[i * SECTOR_SIZE..(i + 1) * SECTOR_SIZE];
            self.0.exclusive_access().read_block(sector + i, s)
                .expect("Error when reading VirtIOBlk");
        }
    }

    /// Write sectors from buffer
    pub fn write_sectors(&self, sector: usize, buf: &[u8]) {
        assert!(buf.len() % SECTOR_SIZE == 0);
        let count = buf.len() / SECTOR_SIZE;
        for i in 0..count {
            let s = &buf[i * SECTOR_SIZE..(i + 1) * SECTOR_SIZE];
            self.0.exclusive_access().write_block(sector + i, s.try_into().unwrap())
                .expect("Error when writing VirtIOBlk");
        }
    }
}

impl VirtIOBlock {
    #[allow(unused)]
    /// Create a new VirtIOBlock driver with given base_addr for virtio_blk device
    pub fn new(base_addr: usize) -> Self {
        unsafe {
            Self(UPSafeCell::new(
                VirtIOBlk::<VirtioHal>::new(&mut *(base_addr as *mut VirtIOHeader)).unwrap(),
            ))
        }
    }
}

pub struct VirtioHal;

impl Hal for VirtioHal {
    fn dma_alloc(pages: usize) -> usize {
        let mut ppn_base = PhysPageNum(0);
        for i in 0..pages {
            let frame = frame_alloc().unwrap();
            if i == 0 { ppn_base = frame.ppn; }
            assert_eq!(frame.ppn.0, ppn_base.0 + i);
            QUEUE_FRAMES.exclusive_access().push(frame);
        }
        let pa: PhysAddr = ppn_base.into();
        pa.0
    }

    fn dma_dealloc(pa: usize, pages: usize) -> i32 {
        let pa = PhysAddr::from(pa);
        let mut ppn_base: PhysPageNum = pa.into();
        for _ in 0..pages {
            frame_dealloc(ppn_base);
            ppn_base.step();
        }
        0
    }

    fn phys_to_virt(addr: usize) -> usize { addr }

    fn virt_to_phys(vaddr: usize) -> usize {
        PageTable::from_token(kernel_token())
            .translate_va(VirtAddr::from(vaddr))
            .unwrap()
            .0
    }
}

