//! Signal flags and function for convert signal flag to integer & string

use bitflags::*;

bitflags! {
    /// Signal flags (bit N = signal N, matching Linux signal numbers)
    pub struct SignalFlags: u32 {
        /// Interrupt
        const SIGINT    = 1 << 2;
        /// Illegal instruction
        const SIGILL    = 1 << 4;
        /// Abort
        const SIGABRT   = 1 << 6;
        /// Floating point exception
        const SIGFPE    = 1 << 8;
        /// Kill (uncatchable)
        const SIGKILL   = 1 << 9;
        /// Segmentation fault
        const SIGSEGV   = 1 << 11;
        /// Alarm clock (from setitimer/alarm)
        const SIGALRM   = 1 << 14;
        /// Termination
        const SIGTERM   = 1 << 15;
    }
}

impl SignalFlags {
    /// convert signal flag to integer & string
    pub fn check_error(&self) -> Option<(i32, &'static str)> {
        if self.contains(Self::SIGKILL) {
            Some((-9, "Killed"))
        } else if self.contains(Self::SIGTERM) {
            Some((-15, "Terminated"))
        } else if self.contains(Self::SIGALRM) {
            Some((-14, "Alarm clock"))
        } else if self.contains(Self::SIGINT) {
            Some((-2, "Killed, SIGINT=2"))
        } else if self.contains(Self::SIGILL) {
            Some((-4, "Illegal Instruction, SIGILL=4"))
        } else if self.contains(Self::SIGABRT) {
            Some((-6, "Aborted, SIGABRT=6"))
        } else if self.contains(Self::SIGFPE) {
            Some((-8, "Erroneous Arithmetic Operation, SIGFPE=8"))
        } else if self.contains(Self::SIGSEGV) {
            Some((-11, "Segmentation Fault, SIGSEGV=11"))
        } else {
            None
        }
    }
}

