/// Wraps a filesystem path with a lazily-opened Ext4File handle.
pub struct Ext4Inode {
    path: String,
    file: UPSafeCell<Option<Ext4File>>,
    file_type: InodeTypes,
}

impl Ext4Inode {
    pub fn new(path: String, file_type: InodeTypes) -> Self {
        Self {
            path,
            file: unsafe { UPSafeCell::new(None) },
            file_type,
        }
    }

    pub fn path(&self) -> &str {
        &self.path
    }

    pub fn file_type(&self) -> InodeTypes {
        self.file_type.clone()
    }

    fn ensure_open(&self, flags: u32) -> Result<(), i32> {
        let mut f = self.file.exclusive_access();
        if f.is_none() {
            let mut file = Ext4File::new(&self.path, InodeTypes::EXT4_DE_REG_FILE);
            file.file_open(&self.path, flags)?;
            *f = Some(file);
        }
        Ok(())
    }

    pub fn read_at(&self, offset: usize, buf: &mut [u8]) -> Result<usize, i32> {
        self.ensure_open(O_RDONLY)?;
        let mut f = self.file.exclusive_access();
        let file = f.as_mut().unwrap();
        file.file_seek(offset as i64, SEEK_SET)?;
        file.file_read(buf)
    }

    pub fn write_at(&self, offset: usize, buf: &[u8]) -> Result<usize, i32> {
        self.ensure_open(O_RDWR)?;
        let mut f = self.file.exclusive_access();
        let file = f.as_mut().unwrap();
        file.file_seek(offset as i64, SEEK_SET)?;
        file.file_write(buf)
    }

    pub fn read_all(&self) -> Vec<u8> {
        // Be defensive: some filesystem metadata paths may report a bogus size.
        // Pre-allocating that size can OOM the kernel during LTP (seen as 40~80 MiB
        // single allocations). Instead, grow the buffer incrementally and cap the
        // total bytes we are willing to read via this convenience helper.
        const READ_ALL_MAX: usize = 32 * 1024 * 1024;

        let reported = self.file_size() as usize;
        let limit = reported.min(READ_ALL_MAX);

        let mut v: Vec<u8> = Vec::new();
        let reserve = limit.min(16 * 1024);
        if reserve != 0 {
            v.reserve(reserve);
        }

        let mut offset = 0usize;
        let mut buf = [0u8; 4096];
        while offset < limit {
            let to_read = (limit - offset).min(buf.len());
            match self.read_at(offset, &mut buf[..to_read]) {
                Ok(0) | Err(_) => break,
                Ok(n) => {
                    offset += n;
                    v.extend_from_slice(&buf[..n]);
                }
            }
        }
        v
    }

    pub fn list_dir(&self) -> Vec<String> {
        if self.file_type != InodeTypes::EXT4_DE_DIR {
            return Vec::new();
        }
        let file = Ext4File::new(&self.path, InodeTypes::EXT4_DE_DIR);
        if let Ok((names, _)) = file.lwext4_dir_entries() {
            names
                .iter()
                .filter_map(|n| {
                    let len = n.iter().position(|&b| b == 0).unwrap_or(n.len());
                    core::str::from_utf8(&n[..len]).ok().map(String::from)
                })
                .collect()
        } else {
            Vec::new()
        }
    }

    pub fn get_entries(&self) -> Vec<(u32, String, u8)> {
        if self.file_type != InodeTypes::EXT4_DE_DIR {
            return Vec::new();
        }
        let file = Ext4File::new(&self.path, InodeTypes::EXT4_DE_DIR);
        if let Ok((names, types)) = file.lwext4_dir_entries() {
            names
                .iter()
                .zip(types.iter())
                .filter_map(|(n, t)| {
                    let len = n.iter().position(|&b| b == 0).unwrap_or(n.len());
                    core::str::from_utf8(&n[..len]).ok().map(|s| {
                        let t_u8 = match t {
                            InodeTypes::EXT4_DE_REG_FILE => 1,
                            InodeTypes::EXT4_DE_DIR => 2,
                            InodeTypes::EXT4_DE_CHRDEV => 3,
                            InodeTypes::EXT4_DE_BLKDEV => 4,
                            InodeTypes::EXT4_DE_FIFO => 5,
                            InodeTypes::EXT4_DE_SOCK => 6,
                            InodeTypes::EXT4_DE_SYMLINK => 7,
                            _ => 0,
                        };
                        (0u32, String::from(s), t_u8)
                    })
                })
                .collect()
        } else {
            Vec::new()
        }
    }

    pub fn lookup(&self, name: &str) -> Option<String> {
        if self.file_type != InodeTypes::EXT4_DE_DIR {
            return None;
        }
        let full_path = if self.path == "/" {
            format!("/{}", name)
        } else {
            format!("{}/{}", self.path, name)
        };

        let mut file = Ext4File::new(&full_path, InodeTypes::EXT4_DE_DIR);
        if file.check_inode_exist(&full_path, InodeTypes::EXT4_DE_DIR) {
            return Some(full_path);
        }
        if file.check_inode_exist(&full_path, InodeTypes::EXT4_DE_REG_FILE) {
            return Some(full_path);
        }
        None
    }

    pub fn file_size(&self) -> u64 {
        if let Ok(()) = self.ensure_open(O_RDONLY) {
            let mut f = self.file.exclusive_access();
            if let Some(file) = f.as_mut() {
                return file.file_size();
            }
        }
        0
    }

    pub fn file_mode(&self) -> u32 {
        if let Ok(()) = self.ensure_open(O_RDONLY) {
            let mut f = self.file.exclusive_access();
            if let Some(file) = f.as_mut() {
                return file.file_mode_get().unwrap_or(0o644);
            }
        }
        0o644
    }
}

impl Drop for Ext4Inode {
    fn drop(&mut self) {
        let mut f = self.file.exclusive_access();
        if let Some(_file) = f.take() {
            drop(_file);
        }
    }
}

