/// futex syscall (Linux RISC-V syscall 98)
///
/// Only FUTEX_WAIT (0) and FUTEX_WAKE (1) are implemented.
/// The private flag (128) is stripped before dispatch.
/// Timeout argument is ignored (treated as infinite wait).
pub fn sys_futex(uaddr: usize, op: u32, val: u32, _timeout: usize, _uaddr2: usize, _val3: u32) -> isize {
    const FUTEX_WAIT: u32 = 0;
    const FUTEX_WAKE: u32 = 1;
    const FUTEX_PRIVATE_FLAG: u32 = 128;
    let base_op = op & !FUTEX_PRIVATE_FLAG;
    match base_op {
        FUTEX_WAIT => {
            // Atomically: if *uaddr == val, block
            let token = current_user_token();
            let current_val = match try_translated_refmut::<i32>(token, uaddr as *mut i32) {
                Some(r) => *r as u32,
                None => return EFAULT,
            };
            if current_val != val {
                return EINTR; // value already changed, don't wait
            }
            let task = current_task().unwrap();
            // Use virtual address as key (works for single-process futex)
            {
                let mut table = FUTEX_TABLE.exclusive_access();
                table.entry(uaddr).or_default().push(Arc::clone(&task));
            }
            block_current_and_run_next();
            // Woken up by FUTEX_WAKE or SIGKILL
            EINTR
        }
        FUTEX_WAKE => {
            let n = val as usize; // number of waiters to wake
            let mut table = FUTEX_TABLE.exclusive_access();
            if let Some(waiters) = table.get_mut(&uaddr) {
                let to_wake: Vec<_> = waiters.drain(..n.min(waiters.len())).collect();
                drop(table);
                for task in to_wake {
                    wakeup_task(task);
                }
            }
            0
        }
        _ => EINVAL,
    }
}

/// rt_sigsuspend: atomically replace signal mask and suspend until signal arrives.
/// We don't implement signal masks, so we just block until any signal is pending.
pub fn sys_rt_sigsuspend(_mask: usize, _sigsetsize: usize) -> isize {
    loop {
        {
            let process = current_process();
            let inner = process.inner_exclusive_access();
            if inner.signals.bits() != 0 {
                return EINTR;
            }
        }
        crate::timer::check_timer();
        crate::task::suspend_current_and_run_next();
    }
}

/// rt_sigtimedwait: enough signal-wait semantics for libc-test's runtest harness.
///
/// The harness forks a child test, then waits for SIGCHLD with a timeout. This
/// kernel tracks fatal signals in a process bitset but does not enqueue SIGCHLD,
/// so report SIGCHLD once a zombie child is visible.
pub fn sys_rt_sigtimedwait(_set: usize, info: usize, timeout: usize, _sigsetsize: usize) -> isize {
    const SIGCHLD: isize = 17;
    let deadline_ms = if timeout == 0 {
        None
    } else {
        let token = current_user_token();
        let ts = try_translated_refmut::<TimeSpec>(token, timeout as *mut TimeSpec)
            .map(|ts| {
                let sec = ts.tv_sec.max(0) as usize;
                let nsec = ts.tv_nsec.max(0).min(999_999_999) as usize;
                sec.saturating_mul(1000).saturating_add(nsec / 1_000_000)
            })
            .unwrap_or(0);
        Some(get_time_ms().saturating_add(ts))
    };

    loop {
        crate::timer::check_timer();
        let process = current_process();
        {
            let inner = process.inner_exclusive_access();
            if inner.children.iter().any(|child| child.inner_exclusive_access().is_zombie) {
                drop(inner);
                if info != 0 {
                    let token = current_user_token();
                    if let Some(bufs) = crate::mm::try_translated_byte_buffer(token, info as *const u8, 128) {
                        for b in bufs {
                            b.fill(0);
                        }
                    }
                    if let Some(signo) = try_translated_refmut::<i32>(token, info as *mut i32) {
                        *signo = SIGCHLD as i32;
                    }
                }
                return SIGCHLD;
            }
            if inner.signals.bits() != 0 {
                return EINTR;
            }
        }
        if let Some(deadline) = deadline_ms {
            if get_time_ms() >= deadline {
                return EAGAIN;
            }
        }
        suspend_current_and_run_next();
    }
}

#[repr(C)]
pub struct TimeSpec {
    pub tv_sec: i64,
    pub tv_nsec: i64,
}

/// sleep syscall (custom, milliseconds)
pub fn sys_sleep(ms: usize) -> isize {
    trace!(
        "kernel:pid[{}] tid[{}] sys_sleep",
        current_task().unwrap().process.upgrade().unwrap().getpid(),
        current_task()
            .unwrap()
            .inner_exclusive_access()
            .res
            .as_ref()
            .unwrap()
            .tid
    );
    let expire_ms = get_time_ms() + ms;
    let task = current_task().unwrap();
    add_timer(expire_ms, task);
    block_current_and_run_next();
    0
}

/// nanosleep syscall (Linux standard, syscall 162)
pub fn sys_nanosleep(req: *const TimeSpec, _rem: *mut TimeSpec) -> isize {
    let token = current_user_token();
    let page_table = PageTable::from_token(token);
    let mut bytes = [0u8; 16];
    let base = req as usize;
    for i in 0..16 {
        let va = VirtAddr::from(base + i);
        if let Some(pa) = page_table.translate_va(va) {
            bytes[i] = unsafe { *(pa.0 as *const u8) };
        } else {
            return EFAULT;
        }
    }
    let mut tv_sec_bytes = [0u8; 8];
