const IPC_CREAT: usize = 0o1000;
const IPC_EXCL: usize = 0o2000;
const IPC_PRIVATE: isize = 0;
const IPC_RMID: usize = 0;
const SHM_RDONLY: usize = 0o10000;

struct ShmSegment {
    key: isize,
    size: usize,
    frames: Vec<FrameTracker>,
    removed: bool,
    nattch: usize,
}

struct ShmTable {
    next_id: usize,
    segments: BTreeMap<usize, ShmSegment>,
}

impl ShmTable {
    fn new() -> Self {
        Self {
            next_id: 1,
            segments: BTreeMap::new(),
        }
    }
}

lazy_static! {
    static ref SHM_TABLE: UPSafeCell<ShmTable> = unsafe { UPSafeCell::new(ShmTable::new()) };
}

fn align_up(value: usize, align: usize) -> usize {
    (value + align - 1) & !(align - 1)
}

pub fn sys_shmget(key: isize, size: usize, shmflg: usize) -> isize {
    if key != IPC_PRIVATE {
        let mut table = SHM_TABLE.exclusive_access();
        if let Some((&id, segment)) = table
            .segments
            .iter()
            .find(|(_, segment)| segment.key == key && !segment.removed)
        {
            if (shmflg & IPC_CREAT) != 0 && (shmflg & IPC_EXCL) != 0 {
                return EEXIST;
            }
            if size != 0 && size > segment.size {
                return EINVAL;
            }
            return id as isize;
        }
        drop(table);
        if (shmflg & IPC_CREAT) == 0 {
            return ENOENT;
        }
    }

    if size == 0 {
        return EINVAL;
    }
    let aligned_size = align_up(size, PAGE_SIZE);
    let page_count = aligned_size / PAGE_SIZE;
    let mut frames = Vec::new();
    for _ in 0..page_count {
        let Some(frame) = frame_alloc() else {
            return ENOMEM;
        };
        frames.push(frame);
    }

    let mut table = SHM_TABLE.exclusive_access();
    let id = table.next_id;
    table.next_id += 1;
    table.segments.insert(
        id,
        ShmSegment {
            key,
            size,
            frames,
            removed: false,
            nattch: 0,
        },
    );
    id as isize
}

pub fn sys_shmat(shmid: usize, shmaddr: usize, shmflg: usize) -> isize {
    let (size, frames): (usize, Vec<PhysPageNum>) = {
        let mut table = SHM_TABLE.exclusive_access();
        let Some(segment) = table.segments.get_mut(&shmid) else {
            return EINVAL;
        };
        if segment.removed {
            return EINVAL;
        }
        segment.nattch += 1;
        (
            align_up(segment.size, PAGE_SIZE),
            segment.frames.iter().map(|frame| frame.ppn).collect(),
        )
    };

    let mut perm = MapPermission::R | MapPermission::U;
    if (shmflg & SHM_RDONLY) == 0 {
        perm |= MapPermission::W;
    }

    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    let start_va = if shmaddr != 0 {
        align_up(shmaddr, PAGE_SIZE)
    } else {
        let addr = align_up(inner.mmap_base, PAGE_SIZE);
        inner.mmap_base = addr + size;
        addr
    };
    if shmaddr != 0 {
        inner.memory_set.remove_area_range(
            VirtAddr::from(start_va).floor(),
            VirtAddr::from(start_va + size).ceil(),
        );
    }
    inner.memory_set.insert_shared_area(
        VirtAddr::from(start_va),
        VirtAddr::from(start_va + size),
        perm,
        frames,
    );
    unsafe {
        asm!("sfence.vma");
    }
    start_va as isize
}

pub fn sys_shmdt(shmaddr: usize) -> isize {
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    inner
        .memory_set
        .remove_area_with_start_vpn(VirtAddr::from(shmaddr).floor());
    0
}

pub fn sys_shmctl(shmid: usize, cmd: usize, buf: usize) -> isize {
    match cmd {
        IPC_RMID => {
            let mut table = SHM_TABLE.exclusive_access();
            let Some(segment) = table.segments.get_mut(&shmid) else {
                return EINVAL;
            };
            segment.removed = true;
            if segment.nattch == 0 {
                table.segments.remove(&shmid);
            }
            0
        }
        // iozone only needs create/attach/detach/remove. Other shmctl queries are harmless no-ops.
        _ => 0,
    }
}

