/// waitpid syscall
///
/// Blocks until a zombie child is available (unless WNOHANG is set).
/// Calls check_timer() in the busy-wait loop so expired timers
/// (e.g. from nanosleep) are processed even though SIE=0.
///
/// options: bit 0 = WNOHANG (return 0 instead of blocking)
///
/// Returns:
///   >0: child PID reaped successfully
///   0:  WNOHANG set, no zombie ready
///   -1: no matching child process exists
pub fn sys_waitpid(pid: isize, exit_code_ptr: *mut i32, options: u32) -> isize {
    const WNOHANG: u32 = 1;
    let process = current_process();
    loop {
        check_timer();
        // Fire ITIMER_REAL: trap_handler only runs at syscall boundary; waitpid spins in
        // kernel mode so we must check the itimer here too, otherwise SIGALRM never fires.
        {
            let mut inner = process.inner_exclusive_access();
            if inner.itimer_real_next_ms > 0 {
                let ms = get_time_ms();
                if ms >= inner.itimer_real_next_ms {
                    inner.signals |= SignalFlags::SIGALRM;
                    if inner.itimer_real_interval_ms > 0 {
                        inner.itimer_real_next_ms += inner.itimer_real_interval_ms;
                    } else {
                        inner.itimer_real_next_ms = 0;
                    }
                }
            }
        }
        // Deliver fatal signals to the current process even while blocked in wait
        {
            let inner = process.inner_exclusive_access();
            if let Some((errno, _msg)) = inner.signals.check_error() {
                drop(inner);
                exit_current_and_run_next(errno);
                loop {}
            }
        }
        let mut inner = process.inner_exclusive_access();
        if !inner
            .children
            .iter()
            .any(|p| pid == -1 || pid as usize == p.getpid())
        {
            return ECHILD;
        }
        let pair = inner.children.iter().enumerate().find(|(_, p)| {
            p.inner_exclusive_access().is_zombie && (pid == -1 || pid as usize == p.getpid())
        });
        if let Some((idx, _)) = pair {
            let child = inner.children.remove(idx);
            let found_pid = child.getpid();
            let exit_code = child.inner_exclusive_access().exit_code;
            // POSIX wait status: signal-killed → signal number in low 7 bits
            // exit_code < 0 means killed by signal -exit_code
            let status = if exit_code < 0 {
                (-exit_code) & 0x7f
            } else {
                exit_code << 8
            };
            if !exit_code_ptr.is_null() {
                let Some(status_ref) =
                    try_translated_refmut(inner.memory_set.token(), exit_code_ptr)
                else {
                    return EFAULT;
                };
                *status_ref = status;
            }
            return found_pid as isize;
        } else if (options & WNOHANG) != 0 {
            return 0;
        }
        drop(inner);
        suspend_current_and_run_next();
    }
}

/// kill syscall
fn kill_send_signal(pid: usize, flag: Option<SignalFlags>) {
    if let Some(process) = pid2process(pid) {
        if let Some(flag) = flag {
            let mut inner = process.inner_exclusive_access();
            inner.signals |= flag;
            let tasks_to_wake: alloc::vec::Vec<_> = inner
                .tasks
                .iter()
                .flatten()
                .filter(|t| t.inner_exclusive_access().task_status == TaskStatus::Blocked)
                .cloned()
                .collect();
            drop(inner);
            for task in tasks_to_wake {
                wakeup_task(task);
            }
        }
    }
}

fn collect_subtree(pid: usize, out: &mut alloc::vec::Vec<usize>) {
    if let Some(proc) = pid2process(pid) {
        out.push(pid);
        let children: alloc::vec::Vec<usize> = proc
            .inner_exclusive_access()
            .children
            .iter()
            .map(|c| c.getpid())
            .collect();
        for cpid in children {
            collect_subtree(cpid, out);
        }
    }
}

pub fn sys_kill(pid: usize, signal: u32) -> isize {
    trace!(
        "kernel:pid[{}] sys_kill signal={}",
        current_task().unwrap().process.upgrade().unwrap().getpid(),
        signal
    );
    if signal == 0 {
        return if pid2process(pid).is_some() { 0 } else { ESRCH };
    }
    if signal >= 32 {
        return EINVAL;
    }
    let flag = SignalFlags::from_bits(1u32 << signal);

    // Negative pid: kill entire process group (all descendants of -pid).
    let pid_isize = pid as isize;
    if pid_isize < -1 {
        let root = (-pid_isize) as usize;
        let mut targets = alloc::vec::Vec::new();
        collect_subtree(root, &mut targets);
        let found = !targets.is_empty();
        for t in targets {
            kill_send_signal(t, flag);
        }
        return if found { 0 } else { ESRCH };
    }

    if pid2process(pid).is_some() {
        kill_send_signal(pid, flag);
        0
    } else {
        ESRCH
    }
}

/// rt_sigprocmask(how, set, oldset, sigsetsize): track the per-process blocked
/// signal mask. musl's sigsetjmp saves the current mask and siglongjmp restores
/// it through this call, so a no-op breaks libctest setjmp. We persist the raw
/// 64-bit mask (signals 1..=64) but do not yet gate delivery on it.
pub fn sys_rt_sigprocmask(how: usize, set: *const u8, oldset: *mut u8, _sigsetsize: usize) -> isize {
    const SIG_BLOCK: usize = 0;
    const SIG_UNBLOCK: usize = 1;
    const SIG_SETMASK: usize = 2;
    let token = current_user_token();
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    if !oldset.is_null() {
        let Some(old_ref) = try_translated_refmut(token, oldset as *mut u64) else {
            return EFAULT;
        };
        *old_ref = inner.signal_mask;
    }
    if !set.is_null() {
        let Some(new_ref) = try_translated_ref(token, set as *const u64) else {
            return EFAULT;
        };
        let new_mask = *new_ref;
        match how {
            SIG_BLOCK => inner.signal_mask |= new_mask,
            SIG_UNBLOCK => inner.signal_mask &= !new_mask,
            SIG_SETMASK => inner.signal_mask = new_mask,
            _ => return EINVAL,
        }
    }
    0
}

