    pub fn from_existed_user(user_space: &Self) -> Self {
        let mut memory_set = Self::new_bare();
        // map trampoline
        memory_set.map_trampoline();
        // copy data sections/trap_context/user_stack
        for area in user_space.areas.iter() {
            let new_area = MapArea::from_another(area);
            if area.is_shared {
                // MAP_SHARED: child maps same physical pages (no copy, no new frames).
                // Parent owns the FrameTrackers; frames live until parent frees them.
                // Safe for LTP pattern: child always exits before parent.
                memory_set.areas.push(new_area);
                let pte_flags = PTEFlags::from_bits(area.map_perm.bits).unwrap_or(PTEFlags::empty());
                for vpn in area.vpn_range {
                    if let Some(pte) = user_space.translate(vpn) {
                        memory_set.page_table.map(vpn, pte.ppn(), pte_flags);
                    }
                }
            } else {
                memory_set.push(new_area, None);
                // copy data from another space
                for vpn in area.vpn_range {
                    let (src_opt, dst_opt) = (user_space.translate(vpn), memory_set.translate(vpn));
                    if let (Some(src_pte), Some(dst_pte)) = (src_opt, dst_opt) {
                        dst_pte
                            .ppn()
                            .get_bytes_array()
                            .copy_from_slice(src_pte.ppn().get_bytes_array());
                    }
                }
            }
        }
        memory_set
    }
