            vpn_range: VPNRange::new(start_vpn, end_vpn),
            data_frames: BTreeMap::new(),
            map_type: MapType::Shared,
            map_perm,
            page_offset: start_va.page_offset(),
            is_shared: true,
            shared_frames,
        }
    }
    pub fn from_another(another: &Self) -> Self {
        Self {
            vpn_range: VPNRange::new(another.vpn_range.get_start(), another.vpn_range.get_end()),
            data_frames: BTreeMap::new(),
            map_type: another.map_type,
            map_perm: another.map_perm,
            page_offset: another.page_offset,
            is_shared: another.is_shared,
            shared_frames: another.shared_frames.clone(),
        }
    }
    fn take_subrange(&mut self, start_vpn: VirtPageNum, end_vpn: VirtPageNum) -> Self {
        let mut data_frames = BTreeMap::new();
        if self.map_type == MapType::Framed {
            let keys: Vec<VirtPageNum> = self
                .data_frames
                .keys()
                .copied()
                .filter(|vpn| *vpn >= start_vpn && *vpn < end_vpn)
                .collect();
            for vpn in keys {
                if let Some(frame) = self.data_frames.remove(&vpn) {
                    data_frames.insert(vpn, frame);
                }
            }
        }

        let shared_frames = if self.map_type == MapType::Shared {
            let base = self.vpn_range.get_start().0;
            let lo = start_vpn.0 - base;
            let hi = end_vpn.0 - base;
            self.shared_frames[lo..hi].to_vec()
        } else {
            Vec::new()
        };

        Self {
            vpn_range: VPNRange::new(start_vpn, end_vpn),
            data_frames,
            map_type: self.map_type,
            map_perm: self.map_perm,
            page_offset: if start_vpn == self.vpn_range.get_start() {
                self.page_offset
            } else {
                0
            },
            is_shared: self.is_shared,
            shared_frames,
        }
    }
    pub fn map_one(&mut self, page_table: &mut PageTable, vpn: VirtPageNum) {
        let ppn: PhysPageNum;
        match self.map_type {
            MapType::Identical => {
                ppn = PhysPageNum(vpn.0);
            }
            MapType::Framed => {
                if self.data_frames.contains_key(&vpn) {
                    return;
                }
                let Some(frame) = frame_alloc() else {
                    log::error!("map_one: frame_alloc OOM for vpn {:?}", vpn);
                    return;
                };
                ppn = frame.ppn;
                self.data_frames.insert(vpn, frame);
            }
            MapType::Shared => {
                let idx = vpn.0 - self.vpn_range.get_start().0;
                ppn = self.shared_frames[idx];
            }
        }
        let pte_flags = PTEFlags::from_bits(self.map_perm.bits).unwrap();
        page_table.map(vpn, ppn, pte_flags);
    }
    pub fn unmap_one(&mut self, page_table: &mut PageTable, vpn: VirtPageNum) {
        if self.map_type == MapType::Framed {
            self.data_frames.remove(&vpn);
        }
        page_table.unmap(vpn);
    }
    pub fn map(&mut self, page_table: &mut PageTable) {
        for vpn in self.vpn_range {
            self.map_one(page_table, vpn);
        }
    }
    pub fn unmap(&mut self, page_table: &mut PageTable) {
        for vpn in self.vpn_range {
            self.unmap_one(page_table, vpn);
        }
    }
    #[allow(unused)]
    pub fn shrink_to(&mut self, page_table: &mut PageTable, new_end: VirtPageNum) {
        for vpn in VPNRange::new(new_end, self.vpn_range.get_end()) {
            self.unmap_one(page_table, vpn)
        }
        self.vpn_range = VPNRange::new(self.vpn_range.get_start(), new_end);
    }
    #[allow(unused)]
    pub fn append_to(&mut self, page_table: &mut PageTable, new_end: VirtPageNum) {
        for vpn in VPNRange::new(self.vpn_range.get_end(), new_end) {
            self.map_one(page_table, vpn)
        }
        self.vpn_range = VPNRange::new(self.vpn_range.get_start(), new_end);
    }
    /// data: start-aligned but maybe with shorter length
    /// assume that all frames were cleared before
    /// data: start-aligned but maybe with shorter length
    /// assume that all frames were cleared before
    pub fn copy_data(&mut self, page_table: &mut PageTable, data: &[u8]) {
        assert_eq!(self.map_type, MapType::Framed);
        let len = data.len();
        if len == 0 { return; }
        let mut start: usize = 0;
        let mut current_vpn = self.vpn_range.get_start();
        let mut page_off = self.page_offset;
        loop {
            let remaining = len - start;
            let copy_size = core::cmp::min(remaining, PAGE_SIZE - page_off);
            if copy_size == 0 { break; }
            let src = &data[start..start + copy_size];
            let dst = &mut page_table
                .translate(current_vpn)
                .unwrap()
                .ppn()
                .get_bytes_array()[page_off..page_off + copy_size];
            dst.copy_from_slice(src);
            start += copy_size;
            if start >= len { break; }
            current_vpn.step();
            page_off = 0;
        }
    }
}

