/// Character device with Linux-like /dev/null and /dev/zero behavior.
pub struct DevNullZero {
    zero: bool,
}

impl DevNullZero {
    /// Create /dev/null when zero is false, or /dev/zero when zero is true.
    pub fn new(zero: bool) -> Self {
        Self { zero }
    }

    fn stat_with_rdev(&self) -> Stat {
        Stat {
            dev: 0, ino: if self.zero { 6 } else { 5 }, mode: 0o020666, nlink: 1,
            uid: 0, gid: 0, rdev: if self.zero { 0x0105 } else { 0x0103 }, _pad0: 0,
            size: 0, blksize: 4096, _pad1: 0, blocks: 0,
            atime_sec: 0, atime_nsec: 0,
            mtime_sec: 0, mtime_nsec: 0,
            ctime_sec: 0, ctime_nsec: 0,
            _unused: [0; 2],
        }
    }
}

impl File for DevNullZero {
    fn readable(&self) -> bool { true }
    fn writable(&self) -> bool { true }
    fn read(&self, mut user_buf: UserBuffer) -> usize {
        if !self.zero {
            return 0;
        }
        let len = user_buf.len();
        for buf in user_buf.buffers.iter_mut() {
            buf.fill(0);
        }
        len
    }
    fn write(&self, user_buf: UserBuffer) -> usize {
        user_buf.len()
    }
    fn stat(&self) -> Option<Stat> {
        Some(self.stat_with_rdev())
    }
}

impl File for Stdin {
    fn readable(&self) -> bool {
        true
    }
    fn writable(&self) -> bool {
        false
    }
    fn read(&self, mut user_buf: UserBuffer) -> usize {
        // Non-blocking stdin: return 1 byte if available, 0 (EOF) if not.
        // Avoids hanging when programs probe stdin during eval.
        let c = console_getchar();
        if c == 0 {
            return 0;
        }
        let ch = c as u8;
        unsafe {
            user_buf.buffers[0].as_mut_ptr().write_volatile(ch);
        }
        1
    }
    fn write(&self, _user_buf: UserBuffer) -> usize {
        panic!("Cannot write to stdin!");
    }
    fn stat(&self) -> Option<Stat> {
        Some(Stat {
            dev: 0, ino: 0, mode: 0o020000, nlink: 1,
            uid: 0, gid: 0, rdev: 0, _pad0: 0,
            size: 0, blksize: 0, _pad1: 0, blocks: 0,
            atime_sec: 0, atime_nsec: 0,
            mtime_sec: 0, mtime_nsec: 0,
            ctime_sec: 0, ctime_nsec: 0,
            _unused: [0; 2],
        })
    }
}

impl File for Stdout {
    fn readable(&self) -> bool {
        false
    }
    fn writable(&self) -> bool {
        true
    }
    fn read(&self, _user_buf: UserBuffer) -> usize {
        panic!("Cannot read from stdout!");
    }
    fn write(&self, user_buf: UserBuffer) -> usize {
        for buffer in user_buf.buffers.iter() {
            print!("{}", core::str::from_utf8(*buffer).unwrap());
        }
        user_buf.len()
    }
    fn stat(&self) -> Option<Stat> {
        Some(Stat {
            dev: 0, ino: 0, mode: 0o020000, nlink: 1,
            uid: 0, gid: 0, rdev: 0, _pad0: 0,
            size: 0, blksize: 0, _pad1: 0, blocks: 0,
            atime_sec: 0, atime_nsec: 0,
            mtime_sec: 0, mtime_nsec: 0,
            ctime_sec: 0, ctime_nsec: 0,
            _unused: [0; 2],
        })
    }
}

