const BLOCK_SIZE: usize = 4096;

/// Simple single-block cache for read/write acceleration.
pub struct VFileCache {
    #[allow(dead_code)]
    data: [u8; BLOCK_SIZE],
    #[allow(dead_code)]
    cached_block: isize,
    #[allow(dead_code)]
    dirty: bool,
}

impl VFileCache {
    /// Create an empty cache.
    pub fn new() -> Self {
        Self {
            data: [0u8; BLOCK_SIZE],
            cached_block: -1,
            dirty: false,
        }
    }

    /// Flush (invalidate) the cache.
    pub fn flush(&mut self) {
        self.dirty = false;
        self.cached_block = -1;
    }
}

/// A file handle wrapping an ext4 inode, tracking a cursor position.
pub struct Ext4File {
    inode_num: u32,
    fs: Arc<Ext4>,
    offset: UPSafeCell<usize>,
    #[allow(dead_code)]
    cache: UPSafeCell<VFileCache>,
}

impl Ext4File {
    /// Open an ext4 file by inode number.
    pub fn new(inode_num: u32, fs: Arc<Ext4>) -> Self {
        Self {
            inode_num,
            fs,
            offset: unsafe { UPSafeCell::new(0) },
            cache: unsafe { UPSafeCell::new(VFileCache::new()) },
        }
    }

    /// Read from the current cursor into `buf`.
    pub fn read(&self, buf: &mut [u8]) -> usize {
        let offset = self.get_offset();
        let len = self.fs.read_at(self.inode_num, offset, buf).unwrap_or(0);
        self.advance(len);
        len
    }

    /// Write `buf` at the current cursor.
    pub fn write(&self, buf: &[u8]) -> usize {
        let offset = self.get_offset();
        let len = self.fs.write_at(self.inode_num, offset, buf).unwrap_or(0);
        self.advance(len);
        len
    }

    /// Seek to an absolute position.
    pub fn seek(&self, pos: usize) {
        *self.offset.exclusive_access() = pos;
    }

    /// Return the current cursor position.
    pub fn tell(&self) -> usize {
        self.get_offset()
    }

    /// Truncate the file to the given size (placeholder).
    pub fn truncate(&self, _size: usize) {
    }

    fn get_offset(&self) -> usize {
        *self.offset.exclusive_access()
    }

    fn advance(&self, n: usize) {
        *self.offset.exclusive_access() += n;
    }
}
